var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"후후훗, 자 봐라.","JPN":"ふふふっ、さあ見なさい。","ENG":"Hah hah, look.","TWN":"呵呵呵，你們看看。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"아무도 너흴 도와주러 오지 못하는구나.","JPN":"誰も貴様らを助けに来ない。","ENG":"No one is coming to help you.","TWN":"沒有人能來幫你們。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"날 봉인에 처박아 넣을 때 나타났던 그 자도……","JPN":"我を封印する時に現れたあの人間も……","ENG":"Even the one who was here when they sealed me...","TWN":"包括把我困在封印時出現的那個人也是……"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"결국 지금은 인간의 명을 다하고 죽어버린 거겠지.","JPN":"結局、すでに人間の寿命で死んでしまったのだろう。","ENG":"I suppose he died of old age.","TWN":"最後，現在應該是結束人類的性命的時候。"},"stage":{"bg":"MAINSTREAM_7010013","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"자, 다음은 누가 될까?","JPN":"さあ、次は誰だ？","ENG":"Now, who’s next?","TWN":"那下一個是誰呢？"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"인간답게, 제 감정을 주체하지 못하고 덤벼드는 자가……","JPN":"人間らしく、自分の感情を剥き出しにして歯向かう者は……","ENG":"Who will be swayed by their emotions and come at me?","TWN":"像個人類一樣，無法克制自己的情緒撲上來的傢伙……"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……당신이 어째서 이렇게까지, 사람을 해치는 괴물이 된 거죠?","JPN":"……あなたはどうしてここまで人を傷つける化け物になってしまったのですか？","ENG":"Why have you become such a monster? Hurting people at whim?","TWN":"……你爲什麼會變成種殘害人類的怪物呢？"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"분노가 식은 뒤의 마음은 어느때보다 차가워질 수 있어.","JPN":"怒りが静まった後の心は、いつにも増して冷たくなるもの。","ENG":"When uncontrollable anger ceases, your heart goes cold like a stone.","TWN":"消氣後的心，會比任何時候都冷靜。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"그래서 난, 너희 인간들을 전부 없애 버리는 대신, 도움을 주기로 했단다.","JPN":"だから我は、貴様ら人間をすべて滅ぼすかわりに、助けてやることにした。","ENG":"So I decided to help you, instead of annihilating you all.","TWN":"所以，我決定幫助你們，而不是把你們全部消滅掉。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"너희 인간들이 더럽혀지기 전에, 내가 직접 그 삶을 거두어가는 거야.","JPN":"貴様ら人間が穢れる前に、我が直接その命をいただくのだ。","ENG":"I will take your lives before you become corrupted.","TWN":"在你們人類受到污染前，我親自去收拾你們的性命。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"그리고, 그 영혼으로 이렇게 예쁜 구슬을 만들어서 영원히 내 곁에 두는 거지.","JPN":"そして、その魂でこのような美しい玉を作り、永遠に我のそばに置く。","ENG":"And I will make pretty orbs with your souls to keep with me forever.","TWN":"然後，用靈魂製作出如此美麗的珠子，永遠留在我身邊。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"이것이, 너희가 그토록 바라던 영생이란다.","JPN":"これが、貴様らがあれだけ望んでいた永遠の命なのだ。","ENG":"This is the eternal life you’ve been wishing for.","TWN":"這就是你們盼望已久的永生。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"복수로군요.","JPN":"復讐なのですね。","ENG":"You’re taking revenge on us.","TWN":"是報仇嗎？"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"沒錯。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"인간은 두 손을 가지고 태어나지만.","JPN":"人間は両手を持って生まれるが。","ENG":"You humans have only two hands.","TWN":"人類出生時有雙手，"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"양손을 가득 채우고도 만족이란 걸 하지 못해.","JPN":"その両手をいっぱいにしても満足なぞできぬ。","ENG":"Yet you never know satisfaction, even when both hands are full.","TWN":"但雙手已經都抓滿東西，卻還是不滿足。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};